```class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        int n = answerKey.size();
        int res = 0, left = 0, count = 0;
        for (int right = 0; right < n; right++) {
            if (answerKey[right] == 'T' || answerKey[right] == 'F') count++;
            while (right - left > k) {
                if (answerKey[left] == 'T' || answerKey[left] == 'F') count--;
                left++;
            }
            res = max(res, count);
        }
        return res;
    }
};```
